import React, { useEffect } from 'react';
import { BrowserRouter as Router, Switch, Route } from "react-router-dom"; // , Redirect
import { useData } from './contexts/index';
import { Layout } from './components';
import {  LandingPage, 
  // BlogPage, 
  ErrorPage } from './pages/index';

const App = () => {
  const { loading, setLoading, setSite } = useData();
  
  useEffect(() => {
    const fetchData = async () => {
      try {
        const result = await fetch(`https://raw.githubusercontent.com/SanjayGoraniya/sanjaygoraniya.github.io/main/siteData.json`);
        const body = await result.json();
        setSite(body);
        setLoading(false);
      } catch(err) {
        setLoading(false);
      }
    }
    fetchData();
  }, [setLoading, setSite]);

  useEffect(() => {
    document.body.classList.toggle("siteLoading", loading);
  }, [loading]);
  
  return (
    <Router>
      <Layout>
        <Switch>
          <Route exact path="/" component={LandingPage} />
          {/* <Route exact path="/blog" component={BlogPage} /> */}
          <Route component={ErrorPage} />
        </Switch>
      </Layout>
    </Router>
  );
}

export default App;