import React, { useEffect } from 'react';
import { useData } from '../contexts/index';
import { handleExternalLinks } from '../utils';

const Page = ({children}) => {
    const { loading } = useData();
    
    useEffect(() => {
        handleExternalLinks();
    }, []);

    return (
        <>
            {loading ? null : children}
        </>
    )
}

export default Page;