/**
 * handleExternalLinks - Sets target="_blank" and rel="noopener noreferrer" for all external links available in current document.
 * @version 2.8.0
 * @returns {Boolean} - return true if any element change else false.
 */
export const handleExternalLinks = () => {
    const ls = Array.from(document.querySelectorAll('a'));
    if (ls && ls.length > 0) {
        ls.forEach((l) => {
            if (l.host !== window.location.host) {
                l.setAttribute('rel', 'noopener noreferrer');
                l.setAttribute('target', '_blank');
            }
            // console.log("handleExternalLink: Element", l);
        })
        return true;
    } else {
        return false;
    }
};
