import React from 'react';
import { useData } from '../contexts/index';
import {
    Intro,
    Background,
    Skills,
    Experience,
    // FeaturedProjects,
    OtherProjects
} from '../components';
import { Page } from './index';

const LandingPage = () => {
    const { site } = useData();

    return (
        <Page>
            <Intro email={`mailto:${site.email}`} />
            <Background email={`mailto:${site.email}`} />
            <Skills skills={site.data.skills} />
            <Experience experience={site.data.experience} />
            {/* <FeaturedProjects /> */}
            <OtherProjects otherProjects={site.data.otherProjects} />
        </Page>
    )
}

export default LandingPage;